{
  "name": "react-typescript-app",
  "version": "1.0.0",
  "description": "React TypeScript app",
  "scripts": {
    "start": "react-scripts start",
    "build": "react-scripts build",
    "test": "react-scripts test",
    "eject": "react-scripts eject"
  },
  "dependencies": {
    "react": "^17.0.2",
    "react-dom": "^17.0.2",
    "react-scripts": "4.0.3",
    "typescript": "^4.1.2"
  },
  "browserslist": {
    "production": [
      ">0.2%",
      "not dead",
      "not op_mini all"
    ],
    "development": [
      "last 1 chrome version",
      "last 1 firefox version",
      "last 1 safari version"
    ]
  }
}

/* Add your global styles here */
body {
  font-family: Arial, sans-serif;
  background-color: #f2f2f2;
}

.container {
  max-width: 960px;
  margin: 0 auto;
  padding: 20px;
}

.title {
  font-size: 24px;
  font-weight: bold;
  margin-bottom: 20px;
}

.button {
  display: inline-block;
  padding: 10px 20px;
  background-color: #007bff;
  color: #fff;
  text-decoration: none;
  border-radius: 5px;
  cursor: pointer;
}

.button:hover {
  background-color: #0056b3;
}

.button-primary {
  background-color: #007bff;
}

.button-secondary {
  background-color: #6c757d;
}

import React from 'react';
import './App.css';

function App() {
  return (
    <div className="container">
      <h1 className="title">React TypeScript App</h1>
      <button className="button button-primary">Primary Button</button>
      <button className="button button-secondary">Secondary Button</button>
    </div>
  );
}

export default App;

/* Reset styles */
body, html {
  margin: 0;
  padding: 0;
}

/* Styles for the root element */
#root {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
  background-color: #f2f2f2;
}

/* Styles for the heading */
.heading {
  font-size: 24px;
  font-weight: bold;
  margin-bottom: 20px;
}

/* Styles for the button */
.button {
  padding: 10px 20px;
  background-color: #007bff;
  color: #fff;
  text-decoration: none;
  border-radius: 5px;
  cursor: pointer;
}

.button:hover {
  background-color: #0056b3;
}

import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import App from './App';

ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')
);

import { reportWebVitals } from './react-app-env';

const sendToAnalytics = (metric: any) => {
  const { id, name, value } = metric;
  // Send the metric data to analytics platform
  console.log(`Metric ID: ${id}, Name: ${name}, Value: ${value}`);
};

reportWebVitals(sendToAnalytics);
